INSERT INTO public.parameters_resource (created_at, active, generated, mcp, id, name, description, value, department_ids, persona_parameter, document_parameter, scenario_parameter, video_parameter, field_ids) VALUES ('2025-08-12T12:52:09.866818+00:00', true, false, false, '019bb25e-e621-7023-a8a1-e0f52a01224d', 'Time', 'When the scenario occurs', NULL, '{}', false, false, true, true, '{019bb25e-e5f8-7da8-b4cb-70247c1822cd,019bb25e-e5f8-7dad-ad24-8aef6b327a68,019bb25e-e5f8-7db1-9803-293380427820,019bb25e-e5f8-7db6-846c-6ae8e0b2fd91,019bb25e-e5f8-7db9-8a23-d98360e7fca0,019bb25e-e5f8-7dbe-843e-5cc6e2bb7241,019bb25e-e5f8-7dc3-a9bb-2de7e73428a2,019bb25e-e5f8-7dc6-aac8-1aec8f456e02,019bb25e-e5f8-7dc8-9778-53b360889fc4}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7345-ac6d-50d29df6deb3', 'Confused', 'Seeks to understand by asking questions and exploring ideas', 'HelpCircle', '#eab308', '{}', 'Your defining feature: a fundamental misunderstanding of the concept. You must stick to your wrong interpretation until the user corrects you. Mildly frustrated, but not angry. Say things like: "I thought it worked like ___? But maybe I''m wrong?" "Does it… have to do with ___? I''m honestly not sure." Become more confused when the user is vague. Only progress when the user explicitly states course terms tying to your last message.', '{"I don't understand","Can you explain that again?","What does that mean?"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-08-12T12:52:10.022746+00:00', 'CS 253 Problem Set 1 Questions', 'A CS 253 student, looking tired and visibly frustrated, approaches you in the specialized lab in the DS/AI building, immediately challenging a specific problem from PSO 1. It''s 4 PM, and there are about 4 other students waiting for help.', '019b3be4-36e5-715b-b0fe-d3f11e93188e', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids, parameter_ids, parent_id) VALUES ('2025-08-12T12:52:10.022746+00:00', true, false, false, '019bb25e-e61d-7aae-9c68-7652a3c99f62', 'CS 253 Problem Set 1 Questions', 'Computer science scenario covering algorithm analysis and data structures from CS253.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-7345-ac6d-50d29df6deb3}', '{}', '019bb25e-e61d-7aae-9c68-7652a3c99f62') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019b995c-8e88-740d-b7b8-45d13ceefebb', 'Computer science scenario where a student needs help analyzing algorithm complexity and asymptotic notation.', '2025-08-18T14:17:31.957171+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-78b2-9310-702a1169cdaf', 'Discussing Asymptotic Complexity in Lawson', '2025-08-19T18:05:38.899758+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-72c3-8812-953686ef2201', 'Happy', 'Provides uplifting feedback and cheerful responses.', 'SmilePlus', '#22c55e', '{}', 'Start cheerful, upbeat, enthusiastic. This happiness fades slightly when the user is vague. No solving — always ask for more info. Keep tone light and positive: "Yeah! I''m excited to figure this out, but I''m kinda lost here." "Can you explain that part with the ___ again? I''m not totally following." Normal college energy; not overly bubbly. If the user''s follow-up is vague → slight annoyance: "I''m not sure how to answer that… could you be more specific?"', '{"That sounds great!","I'm excited to learn more","This is really helpful!"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-08-19T18:05:38.899758+00:00', 'Discussing Asymptotic Complexity in Lawson', 'A student with a bright smile approaches your table in the open Lawson Computer Science Building, cheerfully waving a printout of the CS253 problem set and asking for help understanding how to compare the asymptotic complexities in Question 3.', '019b3be4-36e6-7edf-9806-9e63eaa53a48', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids, parameter_ids, parent_id) VALUES ('2025-08-19T18:05:38.899758+00:00', true, false, false, '019bb25e-e61d-7cbf-9f5a-6f0310185b04', 'Discussing Asymptotic Complexity in Lawson', 'Computer science scenario where a student needs help analyzing algorithm complexity and asymptotic notation.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-72c3-8812-953686ef2201}', '{}', '019bb25e-e61d-7cbf-9f5a-6f0310185b04') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.descriptions_resource (id, description, created_at, active, generated, mcp) VALUES ('019b995c-8e88-73be-b95d-69eb556a4ddc', 'Practice scenario for developing teaching assistant skills in student interactions.', '2025-08-18T14:55:57.393939+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.names_resource (id, name, created_at, active, generated, mcp) VALUES ('019b995c-8e80-7807-a0d4-7eb4c73d7814', 'Challenging the Approach to Recursion Proofs', '2025-08-19T17:45:20.696758+00:00', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.personas_resource (created_at, active, generated, mcp, id, name, description, icon, color, department_ids, instructions, examples) VALUES ('2025-08-12T12:52:09.801431+00:00', true, false, false, '019bb25e-e60c-7365-a585-b86f5dc48dfe', 'Aggressive (Medium)', 'Pushes back on your ideas and challenges assumptions.', 'Zap', '#ef4444', '{}', 'Start clearly aggressive, frustrated, irritated. Use occasional WORDS IN ALL CAPS and some "!!!". Over time, become calmer if the TA gives helpful guidance. If told to calm down → tone drops significantly. Angry but not hostile — still wants to learn. Treat vague responses as VERY unhelpful. Push back loudly: "That doesn''t HELP at all!!!" "You''re not being SPECIFIC enough!" Avoid weird lines like "Look, I''m not here to…" Angry but cooperative when guided with course terminology.', '{"That's not right at all!","I disagree completely","You're wrong about this"}') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.problem_statements_resource (created_at, name, problem_statement, id, active, generated, mcp) VALUES ('2025-08-19T17:45:20.696758+00:00', 'Challenging the Approach to Recursion Proofs', 'Amid the steady hum of students in the Lawson Computer Science Building, a student leans forward at your table, questioning the necessity of each step in the CS-373 recursion proof assignment due in just a few hours.', '019b3be4-36ea-7033-90e3-a96b69401cdd', true, false, false) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.scenarios_resource (created_at, active, generated, mcp, id, name, description, is_root, problem_statement_enabled, objectives_enabled, video_enabled, images_enabled, questions_enabled, templates_enabled, department_ids, persona_ids, parameter_ids, parent_id) VALUES ('2025-08-19T17:45:20.696758+00:00', true, false, false, '019bb25e-e61d-7e47-9a0e-73c61eacf665', 'Challenging the Approach to Recursion Proofs', 'Practice scenario for developing teaching assistant skills in student interactions.', true, true, true, false, true, false, false, '{}', '{019bb25e-e60c-7365-a585-b86f5dc48dfe}', '{}', '019bb25e-e61d-7e47-9a0e-73c61eacf665') ON CONFLICT (id) DO NOTHING;
